// src/error/moxfield.error.ts
var MoxfieldError = class extends Error {
  constructor(status, message) {
    super(message);
    this.status = status;
  }
};

// src/error/not-found.error.ts
var NotFoundMoxfieldError = class extends MoxfieldError {
  constructor(message) {
    super(404, message);
  }
};

// src/fetcher/moxfield.fetcher.ts
function createMoxfieldFetcher(fetcher = fetch) {
  return async function moxfieldFetcher(...arguments_) {
    const response = await fetcher(...arguments_);
    if (response.ok) {
      return response.json();
    }
    if (response.status === 404) {
      throw new NotFoundMoxfieldError();
    }
    const object = await response.json();
    const status = "status" in object ? Number(object.status) : void 0;
    const error = "error" in object ? String(object.error) : void 0;
    throw new MoxfieldError(status, error);
  };
}

