// src/helpers/is-test.ts
function isTest() {
  return typeof process !== "undefined" && process.env.NODE_ENV === "test";
}

// src/helpers/strict.ts
import z from "zod";
function conditionalStrict(schema) {
  if (isTest()) {
    return z.strictObject(schema.shape);
  }
  return schema;
}

