// src/api/deck-list/deck-list.api.ts
var MOXFIELD_DECK_URL_PREFIX = "https://moxfield.com/decks/";
var MOXFIELD_DECK_URL_PREFIX_WWW = "https://www.moxfield.com/decks/";
var API_BASE_URL = "https://api2.moxfield.com";
var deckListIdSchema = z31.coerce.string().describe("DeckList id").transform((value) => {
  const parsed = z31.url().safeParse(value);
  if (parsed.error) {
    return value;
  }
  const url = parsed.data;
  if (url.startsWith(MOXFIELD_DECK_URL_PREFIX) || url.startsWith(MOXFIELD_DECK_URL_PREFIX_WWW)) {
    const replaced = url.replace(MOXFIELD_DECK_URL_PREFIX, "").replace(MOXFIELD_DECK_URL_PREFIX_WWW, "");
    const split = replaced.split("/");
    return split.at(0);
  }
  return parsed.data;
});
var fetchWithZod = createZodFetcher(createMoxfieldFetcher());
var DeckListApi = class {
  async findById(id) {
    const parsed = deckListIdSchema.parse(id);
    return fetchWithZod(deck_list_schema_default, `${API_BASE_URL}/v3/decks/all/${parsed}`, {
      method: "GET"
    });
  }
};
var deck_list_api_default = DeckListApi;

// src/api/index.ts
